322	// applyServerWatchdogConfig reads .ddx/config.yaml at projectRoot and applies
323	// any server.watchdog_deadline / server.stall_deadline overrides. Invalid or
324	// missing values are silently ignored — defaults are filled in by the
325	// watchdog loop at runtime.
326	func (m *WorkerManager) applyServerWatchdogConfig(projectRoot string) {
327		cfg, err := config.LoadWithWorkingDir(projectRoot)
328		if err != nil || cfg == nil || cfg.Server == nil {
329			return
330		}
331		if d, err := time.ParseDuration(cfg.Server.WatchdogDeadline); err == nil && d > 0 {
332			m.WatchdogDeadline = d
333		}
334		if d, err := time.ParseDuration(cfg.Server.StallDeadline); err == nil && d > 0 {
335			m.StallDeadline = d
336		}
337	}
