339	// watchdogDeadlines returns the effective deadlines, applying defaults for
340	// any zero-valued fields.
341	func (m *WorkerManager) watchdogDeadlines() (watchdog, stall, check, grace time.Duration) {
342		watchdog = m.WatchdogDeadline
343		if watchdog <= 0 {
344			watchdog = defaultWatchdogDeadline
345		}
346		stall = m.StallDeadline
347		if stall <= 0 {
348			stall = defaultStallDeadline
349		}
350		check = m.WatchdogCheckInterval
351		if check <= 0 {
352			check = defaultWatchdogCheckInterval
353		}
354		grace = m.WatchdogKillGrace
355		if grace <= 0 {
356			grace = defaultWatchdogKillGrace
357		}
358		return
359	}
