361	func (m *WorkerManager) StartExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
362		// Resolve the effective project root: spec override takes priority over the
363		// manager's default so callers can target any registered project.
364		effectiveRoot := spec.ProjectRoot
365		if effectiveRoot == "" {
366			effectiveRoot = m.projectRoot
367		}
368		spec.ProjectRoot = effectiveRoot
369		spec.ApplyDefaults()
370		if err := spec.Validate(); err != nil {
371			return WorkerRecord{}, err
372		}
373	
374		// Pre-flight: validate harness availability and model compatibility
375		// before creating the worker record or claiming any beads.
376		// Skipped when OpaquePassthrough=true (ddx work path): routing belongs to
377		// the agent service; DDx must not pre-resolve or validate the route.
378		if !spec.OpaquePassthrough {
379			if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider); err != nil {
380				return WorkerRecord{}, fmt.Errorf("work: %w", err)
381			}
382		}
383	
384		if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
385			return WorkerRecord{}, err
386		}
387	
388		id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
389		dir := filepath.Join(m.rootDir, id)
390		if err := os.MkdirAll(dir, 0o755); err != nil {
391			return WorkerRecord{}, err
392		}
393	
394		// Write spec
395		specData, _ := json.MarshalIndent(spec, "", "  ")
396		_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)
397	
398		// Open log file
399		logPath := filepath.Join(dir, "worker.log")
400		logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
401		if err != nil {
402			return WorkerRecord{}, err
403		}
404	
405		// Open structured event sink — loop milestones (bead.claimed, bead.result,
406		// loop.start/end) land here as JSONL so log aggregators and future server
407		// endpoints can parse them independently of the human-readable worker.log.
408		eventsPath := filepath.Join(dir, "worker-events.jsonl")
409		eventsFile, eventsErr := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
410		if eventsErr != nil {
411			eventsFile = nil // non-fatal; structured events silently disabled
412		}
413	
414		record := WorkerRecord{
415			ID:           id,
416			Kind:         "work",
417			State:        "running",
418			Status:       "running",
419			ProjectRoot:  effectiveRoot,
420			Harness:      spec.Harness,
421			Model:        spec.Model,
422			Profile:      agent.NormalizeRoutingProfile(spec.Profile),
423			Effort:       spec.Effort,
424			Once:         executeLoopOnce(spec),
425			PollInterval: executeLoopPollInterval(spec).String(),
426			StdoutPath:   relToProject(m.projectRoot, logPath),
427			SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
428			StartedAt:    time.Now().UTC(),
429		}
430		record.Lifecycle = append(record.Lifecycle, WorkerLifecycleEvent{
431			Action:    "start",
432			Actor:     "local-operator",
433			Timestamp: record.StartedAt,
434			Detail:    lifecycleStartDetail(spec),
435		})
436		_ = m.writeRecord(dir, record)
437	
438		ctx, cancel := context.WithCancel(context.Background())
439		logBuf := &bytes.Buffer{}
440		multiLog := io.MultiWriter(logBuf, logFile)
441	
442		progressCh := make(chan agent.ProgressEvent, 64)
443		wakeCh := make(chan struct{}, 1)
444		handle := &workerHandle{
445			record:       record,
446			cancel:       cancel,
447			logBuf:       logBuf,
448			logFile:      logFile,
449			progressCh:   progressCh,
450			progressDone: make(chan struct{}),
451			lastPhaseTS:  time.Now().UTC(),
452			wakeCh:       wakeCh,
453		}
454	
455		m.mu.Lock()
456		m.workers[id] = handle
457		m.mu.Unlock()
458	
459		m.ensureWatchdog()
460	
461		go m.drainProgress(id, handle, progressCh)
462		go m.runWorker(ctx, id, dir, spec, effectiveRoot, handle, multiLog, eventsFile, progressCh)
463	
464		return record, nil
465	}
