542	func (m *WorkerManager) runPluginAction(ctx context.Context, id, dir string, spec PluginActionWorkerSpec, handle *workerHandle, log io.Writer, progressCh chan agent.ProgressEvent, run PluginActionExecutor) {
543		startedAt := time.Now().UTC()
544		phaseSeq := 1
545		sendProgress(progressCh, agent.ProgressEvent{
546			EventID:   "evt-" + randomSuffix(8),
547			AttemptID: id,
548			WorkerID:  id,
549			ProjectID: spec.ProjectRoot,
550			Phase:     "running",
551			PhaseSeq:  phaseSeq,
552			TS:        startedAt,
553			Message:   fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
554		})
555		if log != nil {
556			_, _ = fmt.Fprintf(log, "%s plugin %s (%s)\n", spec.Action, spec.Name, spec.Scope)
557		}
558	
559		state, err := run(ctx)
560		if ctxErr := ctx.Err(); ctxErr != nil && err == nil {
561			err = ctxErr
562		}
563	
564		phase := "done"
565		message := state
566		if err != nil {
567			phase = "failed"
568			message = err.Error()
569		}
570		phaseSeq++
571		sendProgress(progressCh, agent.ProgressEvent{
572			EventID:   "evt-" + randomSuffix(8),
573			AttemptID: id,
574			WorkerID:  id,
575			ProjectID: spec.ProjectRoot,
576			Phase:     phase,
577			PhaseSeq:  phaseSeq,
578			TS:        time.Now().UTC(),
579			ElapsedMS: time.Since(startedAt).Milliseconds(),
580			Message:   message,
581		})
582	
583		if log != nil {
584			if err != nil {
585				_, _ = fmt.Fprintf(log, "failed: %s\n", err)
586			} else {
587				_, _ = fmt.Fprintf(log, "completed: %s\n", state)
588			}
589		}
590	
591		close(progressCh)
592		<-handle.progressDone
593	
594		m.mu.Lock()
595		record := handle.record
596		preservedState := ""
597		if record.State == "stopped" || record.State == "reaped" {
598			preservedState = record.State
599		}
600		record.FinishedAt = time.Now().UTC()
601		_ = handle.logFile.Close()
602		if err != nil {
603			record.State = "failed"
604			record.Status = "failed"
605			record.Error = err.Error()
606			record.LastError = err.Error()
607		} else {
608			record.State = "exited"
609			record.Status = "success"
610			record.LastResult = &WorkerExecutionResult{
611				AttemptID:  id,
612				WorkerID:   id,
613				PowerClass: "",
614				Status:     state,
615				Detail:     fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
616			}
617		}
618		if preservedState != "" {
619			record.State = preservedState
620			record.Status = preservedState
621		}
622		_ = m.writeRecord(dir, record)
623		handle.record = record
624		m.mu.Unlock()
625	}
