638	func nextEscalationFloor(l *powerladder.Ladder, actualPower int) (int, error) {
639		if l == nil {
640			return 0, powerladder.ErrLadderExhausted
641		}
642		floor := actualPower
643		for {
644			next, err := l.Next(floor)
645			if err == nil {
646				return next, nil
647			}
648			var nvp *powerladder.NoViableProviderError
649			if errors.As(err, &nvp) {
650				floor = nvp.Floor
651				continue
652			}
653			return 0, err
654		}
655	}
656	
657	type tryLoopFloorFinder struct {
658		ladder *powerladder.Ladder
659	}
660	
661	func (f tryLoopFloorFinder) Next(actualPower int) (int, error) {
662		return nextEscalationFloor(f.ladder, actualPower)
663	}
664	
665	func runEscalatingPowerAttempts(
666		ctx context.Context,
667		initialMinPower int,
668		ladder *powerladder.Ladder,
669		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
670		recordAttempt func(agent.ExecuteBeadReport),
671		allowInfrastructureRetry bool,
672	) (agent.ExecuteBeadReport, error) {
673		minPower := initialMinPower
674		floors := tryLoopFloorFinder{ladder: ladder}
675		for {
676			report, err := attempt(ctx, minPower)
677			if recordAttempt != nil && report.BeadID != "" {
678				recordAttempt(report)
679			}
680			if err != nil {
681				return report, err
682			}
683			transition := executeloop.DecideAttemptTransition(executeloop.AttemptTransitionInput{
684				Status:                   report.Status,
685				Detail:                   report.Detail,
686				CurrentMinPower:          minPower,
687				ActualPower:              report.ActualPower,
688				Disrupted:                report.Disrupted,
689				BudgetExhausted:          isBudgetExhaustedFailure(report),
690				AllowInfrastructureRetry: allowInfrastructureRetry,
691			}, floors)
692			if transition.Action != executeloop.TryLoopActionRetryPower {
693				return report, nil
694			}
695			minPower = transition.NextMinPower
696		}
697	}
