718	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
719		if eventSink != nil {
720			defer eventSink.Close() //nolint:errcheck
721		}
722		store := bead.NewStore(ddxroot.JoinProject(projectRoot))
723		overrides := config.CLIOverrides{
724			Assignee:          "ddx",
725			Harness:           spec.Harness,
726			Model:             spec.Model,
727			Provider:          spec.Provider,
728			Profile:           agent.NormalizeRoutingProfile(spec.Profile),
729			Effort:            spec.Effort,
730			MinPower:          spec.MinPower,
731			MaxPower:          spec.MaxPower,
732			OpaquePassthrough: spec.OpaquePassthrough,
733		}
734		requestTimeout := spec.RequestTimeout.Duration
735		if requestTimeout > 0 {
736			overrides.ProviderRequestTimeout = &requestTimeout
737		}
738		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
739	
740		var lintHook func(ctx context.Context, beadID string) (agent.LintResult, error)
741		var intakeHook agent.PreClaimIntakeHook
742		var triageHook func(ctx context.Context, beadID string, report agent.ExecuteBeadReport) (agent.TriageResult, error)
743		if m.BeadWorkerFactory == nil {
744			var qualityRunner agent.AgentRunner
745			lintHook = agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
746			intakeHook = agent.NewPreClaimIntakeHookWithLog(projectRoot, store, rcfg, nil, qualityRunner, log)
747			intakeHook = agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), intakeHook)
748			triageHook = agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
749		}
750	
751		var worker *agent.ExecuteBeadWorker
752		var costCap *policyescalation.CostCapTracker
753		if m.BeadWorkerFactory != nil {
754			worker = m.BeadWorkerFactory(store)
755		} else {
756			// Build an executor that calls agent.ExecuteBead in-process, then
757			// submits the result to the project's land coordinator. The
758			// coordinator (a single goroutine per projectRoot) serializes all
759			// target-ref writes for this project — this is the server-side
760			// implementation of the human-PR landing model. See ddx-8746d8a6
761			// for the rationale. Prior to this rewrite, runWorker never called
762			// LandBeadResult at all, so commits produced by server-managed
763			// workers were silently lost (ddx-e14efc58).
764			coordinator := m.LandCoordinators.Get(projectRoot)
765	
766			// singlePolicyAttempt runs one execution at a specific harness/model.
767			// The caller controls MinPower per rung; this helper keeps the
768			// profile stable and only advances the power floor.
769			singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
770				gitOps := &agent.RealGitOps{}
771				attemptProvider := spec.Provider
772				if resolvedProvider != "" {
773					attemptProvider = resolvedProvider
774				}
775				loopOverrides := config.CLIOverrides{
776					Harness:           resolvedHarness,
777					Model:             resolvedModel,
778					Provider:          attemptProvider,
779					Profile:           rcfg.Profile(),
780					Effort:            spec.Effort,

 780					Effort:            spec.Effort,
 781					MinPower:          requestedMinPower,
 782					MaxPower:          spec.MaxPower,
 783					OpaquePassthrough: spec.OpaquePassthrough,
 784				}
 785				if requestTimeout > 0 {
 786					loopOverrides.ProviderRequestTimeout = &requestTimeout
 787				}
 788				attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
 789				beadStore := bead.NewStore(ddxroot.JoinProject(projectRoot))
 790				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
 791					FromRev:          spec.FromRev,
 792					BeadEvents:       beadStore,
 793					BeadCancel:       beadStore,
 794					RateLimitMaxWait: spec.RateLimitMaxWait.Duration,
 795				}, gitOps)
 796				if err != nil && res == nil {
 797					return agent.ExecuteBeadReport{}, err
 798				}
 799				// Preserve operator-cancel results as-is; the worker has already
 800				// classified them (preserved / operator_cancel / preserved_needs_review)
 801				// and overriding here would lose the cancel signal.
 802				operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
 803				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
 804					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
 805						err = landErr
 806					}
 807				} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
 808					res.Outcome = "no-changes"
 809					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
 810				} else if res != nil && res.ExitCode != 0 && !operatorCancel {
 811					res.Outcome = "preserved"
 812					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
 813				}
 814				// Safety net: commit any leftover evidence files that Land()
 815				// did not pick up (e.g. HEAD was detached, or no land ran).
 816				if res != nil && res.AttemptID != "" {
 817					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
 818				}
 819				if err != nil {
 820					return agent.ExecuteBeadReport{}, err
 821				}
 822				return agent.ExecuteBeadReport{
 823					BeadID:             res.BeadID,
 824					AttemptID:          res.AttemptID,
 825					WorkerID:           res.WorkerID,
 826					Harness:            res.Harness,
 827					Provider:           res.Provider,
 828					Model:              res.Model,
 829					ActualPower:        res.ActualPower,
 830					Status:             res.Status,
 831					Detail:             res.Detail,
 832					SessionID:          res.SessionID,
 833					BaseRev:            res.BaseRev,
 834					ResultRev:          res.ResultRev,
 835					ImplementationRev:  res.ImplementationRev,
 836					LandedRev:          res.LandedRev,
 837					EvidenceRev:        res.EvidenceRev,
 838					PreserveRef:        res.PreserveRef,
 839					NoChangesRationale: res.NoChangesRationale,
 840					CostUSD:            res.CostUSD,
 841					DurationMS:         int64(res.DurationMS),
 842				}, nil
 843			}
 844	
 845			// Cost-cap state for this worker run. Subscription / local providers do
 846			// not contribute (see escalation.CountsTowardCostCap).
 847			maxCostUSD := executeLoopMaxCostUSD(spec)
 848			var ladderOnce sync.Once
 849			var ladder *powerladder.Ladder
 850			loadLadder := func() *powerladder.Ladder {
 851				ladderOnce.Do(func() {
 852					ladder = powerladder.NewLadder(nil)
 853					modelCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
 854					defer cancel()
 855					// Tie the fizeau service to modelCtx so its background probe
 856					// goroutines terminate when this short-lived lookup ends.
 857					if svc, svcErr := agent.NewServiceFromWorkDirCtx(modelCtx, projectRoot); svcErr == nil {
 858						modelFilter := agentlib.ModelFilter{}
 859						if harness := rcfg.Harness(); harness != "" {
 860							modelFilter.Harness = harness
 861						}
 862						if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
 863							ladder = powerladder.NewLadder(models)
 864						}
 865					}
 866				})
 867				return ladder
 868			}
 869			costCap = policyescalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
 870				// Per-callback bounded ctx so fizeau probe goroutines do not
 871				// outlive this cost-cap check.
 872				cbCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
 873				defer cancel()
 874				svc, svcErr := agent.NewServiceFromWorkDirCtx(cbCtx, projectRoot)
 875				if svcErr != nil {
 876					return true
 877				}
 878				infos, err := svc.ListHarnesses(cbCtx)
 879				if err != nil {
 880					return true
 881				}
 882				for _, h := range infos {
 883					if h.Name == harnessName {
 884						return policyescalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
 885					}
 886				}
 887				return true
 888			})
 889			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
