 98	// RunWithConfigViaService dispatches a single agent invocation through the
 99	// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
100	// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
101	// successor to the retired RunViaService/RunViaServiceWith entry points.
102	//
103	// The virtual and script harnesses route through a DDx-owned Runner path,
104	// not the upstream service. These are not "carve-outs pending migration" —
105	// they are different products from upstream's same-named stubs. DDx's
106	// virtual is a content-addressed record/replay dictionary keyed by
107	// PromptHash; upstream's is a unit-test stub where callers stuff
108	// virtual.response into Metadata. DDx's script reads a filesystem directive
109	// file; upstream does not model this at all.
110	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
111		if ctx == nil {
112			ctx = context.Background()
113		}
114	
115		harness := rcfg.Passthrough().Harness
116	
117		effectivePerms := runtime.PermissionsOverride
118		if effectivePerms == "" {
119			effectivePerms = rcfg.Permissions()
120		}
121		if err := ValidateReadOnlyReviewerDispatch(harness, effectivePerms); err != nil {
122			return nil, err
123		}
124	
125		if harness == "virtual" || harness == "script" {
126			sessionLogDir := runtime.SessionLogDirOverride
127			if sessionLogDir == "" {
128				sessionLogDir = rcfg.SessionLogDir()
129			}
130			cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
131			r := NewRunner(cfg)
132			r.WorkDir = workDir
133			return r.runInternal(RunArgs{
134				Context:       ctx,
135				Harness:       rcfg.Harness(),
136				Prompt:        runtime.Prompt,
137				PromptFile:    runtime.PromptFile,
138				PromptSource:  runtime.PromptSource,
139				Correlation:   runtime.Correlation,
140				Model:         rcfg.Model(),
141				Provider:      rcfg.Provider(),
142				Effort:        rcfg.Effort(),
143				Timeout:       rcfg.Timeout(),
144				WallClock:     rcfg.WallClock(),
145				WorkDir:       runtime.WorkDir,
146				Permissions:   rcfg.Permissions(),
147				SessionLogDir: sessionLogDir,
148				Env:           runtime.Env,
149			})
150		}
151	
152		svc, err := ResolvePreflightServiceFromWorkDir(workDir)
153		if err != nil {
154			return nil, fmt.Errorf("agent: build service: %w", err)
