159	// executeOnService dispatches against a pre-built svc using the durable
160	// knobs from rcfg and per-invocation plumbing from runtime, then records
161	// one session-index row. It is the inlined replacement for the retired
162	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
163	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
164		if svc == nil {
165			return nil, fmt.Errorf("agent: nil service")
166		}
167		if ctx == nil {
168			ctx = context.Background()
169		}
170	
171		promptText := runtime.Prompt
172		if runtime.PromptFile != "" {
173			data, err := readPromptFileBounded(runtime.PromptFile)
174			if err != nil {
175				return nil, fmt.Errorf("agent: read prompt file: %w", err)
176			}
177			promptText = string(data)
178		}
179		if promptText == "" {
180			return nil, fmt.Errorf("agent: prompt is required")
181		}
182	
183		wd := runtime.WorkDir
184		if wd == "" {
185			wd = workDir
186		}
187		if wd == "" {
188			wd, _ = os.Getwd()
189		}
190	
191		idle := rcfg.Timeout()
192		if idle <= 0 {
193			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
194		}
195		wall := rcfg.WallClock()
196		if wall <= 0 {
197			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
198		}
199	
200		sessionLogDir := runtime.SessionLogDirOverride
201		if sessionLogDir == "" {
202			sessionLogDir = rcfg.SessionLogDir()
203		}
204		if sessionLogDir == "" {
205			sessionLogDir = ResolveLogDir(workDir, "")
206		}
207	
208		pt := rcfg.Passthrough()
209	
210		harness := runtime.HarnessOverride
211		if harness == "" && !runtime.ClearRoutingPins {
212			harness = pt.Harness
213		}
214	
215		model := runtime.ModelOverride
216		if model == "" && !runtime.ClearRoutingPins {
217			model = pt.Model
218		}
219	
220		provider := runtime.ProviderOverride
221		if provider == "" && !runtime.ClearRoutingPins {
222			provider = pt.Provider
223		}
224		if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
225			provider = ""
226		}
227	
228		profile := runtime.ProfileOverride
229		if profile == "" && !runtime.ClearProfile {
230			profile = rcfg.Profile()
231		}
232	
233		permissions := runtime.PermissionsOverride
234		if permissions == "" {
235			permissions = rcfg.Permissions()
236		}
237	
238		providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())
239	
240		minPower := rcfg.MinPower()
241		if runtime.MinPowerOverride > 0 {
242			minPower = runtime.MinPowerOverride
243		}
244		if runtime.ClearMinPower {
245			minPower = 0
246		}
247		maxPower := rcfg.MaxPower()
248		if runtime.ClearMaxPower {
249			maxPower = 0
250		}
251		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
252			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
253		}
254	
255		req := agentlib.ServiceExecuteRequest{
256			Prompt:                promptText,
257			Model:                 model,
258			Policy:                profile,
259			Provider:              provider,
260			Harness:               fizeauHarness(harness),

260			Harness:               fizeauHarness(harness),
261			Reasoning:             agentlib.Reasoning(rcfg.Effort()),
262			Permissions:           permissions,
263			WorkDir:               wd,
264			Timeout:               wall,
265			IdleTimeout:           idle,
266			ProviderTimeout:       providerTimeout,
267			SessionLogDir:         sessionLogDir,
268			Metadata:              metadataWithEnv(runtime.Correlation, runtime.Env),
269			Role:                  runtime.Role,
270			CorrelationID:         runtime.CorrelationID,
271			MinPower:              minPower,
272			MaxPower:              maxPower,
273			EstimatedPromptTokens: firstPositiveInt(runtime.EstimatedPromptTokens, estimatePromptTokens(promptText)),
274			RequiresTools:         runtime.RequiresTools,
275		}
276		seedRecentRouteAttemptsFromTracker(ctx, svc, workDir, time.Now().UTC())
277	
278		cancelCtx, cancel := context.WithCancel(ctx)
279		defer cancel()
280	
281		// When Harness is set and Model is empty, fizeau routes within the harness's
282		// eligible models using Profile/MinPower as the routing constraint. This is the
283		// well-formed request shape for profile-driven dispatch without an explicit model.
284		// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
285		// errors and a failed final event for post-dispatch errors.
286		start := time.Now().UTC()
287		events, err := svc.Execute(cancelCtx, req)
288		if err != nil {
289			// A pre-dispatch Execute error means routing never produced a viable
290			// dispatch — a provider-boundary failure. Wrap it with its typed
291			// classification (ddx-3b721804) so callers recover the taxonomy via
292			// errors.As instead of re-parsing free text, and so the failure
293			// surfaces as a typed outcome_reason rather than generic execution_failed.
294			return nil, &ProviderFailureError{
295				Failure: ClassifyServiceExecuteError(err),
296				Err:     fmt.Errorf("agent: execute: %w", err),
297			}
298		}
299	
300		workPhase := strings.TrimSpace(runtime.WorkLogPhase)
301		if workPhase == "" {
302			workPhase = "do"
303		}
304		renderer := NewWorkLogRenderer(WorkLogRendererOptions{
305			CurrentBeadID: runtime.Correlation["bead_id"],
306			WorkPhase:     workPhase,
307		})
308		watchdog := &drainWatchdog{
309			cancel:          cancel,
310			idleTimeout:     idle,
311			toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
312		}
313		onRouteResolved := func(harness, provider, model string) {
314			harness = firstNonEmpty(harness, fizeauHarness(strings.TrimSpace(runtime.HarnessOverride)), fizeauHarness(strings.TrimSpace(pt.Harness)))
315			provider = firstNonEmpty(provider, strings.TrimSpace(runtime.ProviderOverride), strings.TrimSpace(pt.Provider))
316			model = firstNonEmpty(model, strings.TrimSpace(runtime.ModelOverride), strings.TrimSpace(pt.Model))
317			route := providerRouteLabel(provider, model)
318			now := time.Now().UTC()
319			reaped, survivors := reapSupersededProviderChildren(context.Background(), os.Getpid(), route, harness, now)
320			if len(reaped) > 0 {
321				writeProviderChildCleanupArtifact(workDir, runtime.Correlation["attempt_id"], &providerChildCleanupReport{
322					AttemptID:   runtime.Correlation["attempt_id"],
323					BeadID:      runtime.Correlation["bead_id"],
324					Trigger:     reasonSupersededProviderChild,
325					ActiveRoute: firstNonEmpty(route, harness),
326					ScannedAt:   now,
327					Survivors:   survivors,
328					Reaped:      reaped,
329				})
330			}
331			if runtime.OnRouteResolved != nil {
332				runtime.OnRouteResolved(harness, provider, model)
333			}
334		}
335		final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog, onRouteResolved)
336		if final == nil {
337			// Provider process exited before emitting a final event — a harness-level
338			// failure (crash, OOM, binary restart) the model never saw. Classify as
339			// harness unavailable (retryable) so an unpinned worker can fall back to
340			// another eligible route without operator intervention.
341			return nil, &ProviderFailureError{
342				Failure: ProviderFailure{
343					Reason:     FailureModeProviderHarnessUnavailable,
344					Retryable:  true,
345					Disruption: FailureModeProviderHarnessUnavailable,
346				},
347				Err: fmt.Errorf("agent: provider process exited without emitting a final event"),
348			}
349		}
350		finishedAt := time.Now().UTC()
351		elapsed := finishedAt.Sub(start)
352	
353		result := &Result{
354			Harness:    fizeauHarness(harness),
355			Model:      model,
356			DurationMS: int(elapsed.Milliseconds()),
357		}
358		if routing != nil {
359			result.Provider = routing.Provider
360			if routing.Model != "" {
361				result.Model = routing.Model
362			}
363			if routing.Harness != "" {
364				result.Harness = routing.Harness
365			}
366			if routing.Reason != "" {
367				result.RouteReason = routing.Reason
368			}
369			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
370				result.PredictedPower = power
371				result.PredictedSpeedTPS = speed
372				result.PredictedCostUSDPer1kTokens = cost
373				result.PredictedCostSource = source
374			}
375		}
376		if final != nil {
377			// Normalized final text from the upstream harness (agent-32e8ff5e);
378			// reviewer verdict extraction now parses this instead of raw stream
379			// frames (ddx-7bc0c8d5).
380			result.Output = final.FinalText
381			if final.Usage != nil {
382				// v0.9.1: Usage fields became *int (nullable).
383				if final.Usage.InputTokens != nil {
384					result.InputTokens = *final.Usage.InputTokens
385				}
386				if final.Usage.OutputTokens != nil {
387					result.OutputTokens = *final.Usage.OutputTokens
388				}
389				if final.Usage.CacheReadTokens != nil {
390					result.CachedTokens = *final.Usage.CacheReadTokens
391				}
392				if final.Usage.TotalTokens != nil {
393					result.Tokens = *final.Usage.TotalTokens
394				}
395			}
396			if final.CostUSD > 0 {
397				result.CostUSD = final.CostUSD
398			}
399			result.ExitCode = final.ExitCode
400			result.Error = final.Error
401			if final.RoutingActual != nil {
402				if result.Provider == "" {
403					result.Provider = final.RoutingActual.Provider
404				}
405				if final.RoutingActual.Model != "" {
406					result.Model = final.RoutingActual.Model
407				}
408				if final.RoutingActual.Harness != "" {
409					result.Harness = final.RoutingActual.Harness
410				}
411				if final.RoutingActual.Power > 0 {
412					result.ActualPower = final.RoutingActual.Power
413				}
414			}
415			if final.SessionLogPath != "" {
416				result.AgentSessionID = final.SessionLogPath
417			}
418		}
419		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
420		normalizeServiceFinalExitCode(result)

