 85	// readinessVerdict is the verdict reported for a single readiness check.
 86	// Keep this coercion aligned with cli/internal/agent/schema/readiness-checks.schema.json
 87	// so the shared producer prompt and this decoder accept the same payload shape.
 88	// The intake producer may emit verdict as a JSON bool, a JSON string, or omit
 89	// it entirely; UnmarshalJSON coerces all three forms to a canonical lowercased
 90	// string so downstream fail-detection (failedReadinessReasons) can compare it
 91	// deterministically:
 92	//   - JSON bool true  -> "pass"
 93	//   - JSON bool false -> "fail"
 94	//   - JSON string     -> trimmed, lowercased value (for example "PASS" -> "pass")
 95	//   - absent / null   -> "" (empty, same as a missing field)
 96	type readinessVerdict string
 97	
 98	func (v *readinessVerdict) UnmarshalJSON(data []byte) error {
 99		trimmed := strings.TrimSpace(string(data))
100		if trimmed == "" || trimmed == "null" {
101			*v = ""
102			return nil
103		}
104		switch trimmed[0] {
105		case 't', 'f':
106			var b bool
107			if err := json.Unmarshal(data, &b); err != nil {
108				return err
109			}
110			if b {
111				*v = "pass"
112			} else {
113				*v = "fail"
114			}
115			return nil
116		case '"':
117			var s string
118			if err := json.Unmarshal(data, &s); err != nil {
119				return err
120			}
121			*v = readinessVerdict(strings.ToLower(strings.TrimSpace(s)))
122			return nil
123		default:
124			return fmt.Errorf("readiness_checks verdict must be a bool, string, or null, got %s", jsonKindName(trimmed[0]))
125		}
126	}
127	
128	func jsonKindName(first byte) string {
129		switch first {
130		case '{':
131			return "object"
132		case '[':
133			return "array"
134		case '"':
135			return "string"
136		case 't', 'f':
137			return "bool"
138		case 'n':
139			return "null"
140		default:
141			return "number"
142		}
143	}
