168	type preClaimReadinessSuggestedFixesPayload []preClaimReadinessSuggestedFix
169	
170	func (p *preClaimReadinessSuggestedFixesPayload) UnmarshalJSON(data []byte) error {
171		trimmed := strings.TrimSpace(string(data))
172		if trimmed == "" || trimmed == "null" {
173			return nil
174		}
175		if trimmed[0] != '[' {
176			return fmt.Errorf("suggested_fixes must be a JSON array")
177		}
178		var raw []json.RawMessage
179		if err := json.Unmarshal(data, &raw); err != nil {
180			return err
181		}
182		fixes := make([]preClaimReadinessSuggestedFix, 0, len(raw))
183		for _, item := range raw {
184			itemTrimmed := strings.TrimSpace(string(item))
185			if itemTrimmed == "" || itemTrimmed == "null" {
186				continue
187			}
188			switch itemTrimmed[0] {
189			case '"':
190				var fix string
191				if err := json.Unmarshal(item, &fix); err != nil {
192					return err
193				}
194				fixes = append(fixes, preClaimReadinessSuggestedFix{Fix: strings.TrimSpace(fix)})
195			case '{':
196				var fix preClaimReadinessSuggestedFix
197				if err := json.Unmarshal(item, &fix); err != nil {
198					return err
199				}
200				fix.Target = strings.TrimSpace(fix.Target)
201				fix.Fix = strings.TrimSpace(fix.Fix)
202				fixes = append(fixes, fix)
203			default:
204				return fmt.Errorf("suggested_fixes entries must be strings or objects")
205			}
206		}
207		*p = fixes
208		return nil
209	}
