229	func decodeReadinessStringListField(data []byte, fieldName string, splitLines bool) ([]string, error) {
230		trimmed := strings.TrimSpace(string(data))
231		if trimmed == "" || trimmed == "null" {
232			return nil, nil
233		}
234		switch trimmed[0] {
235		case '[':
236			var items []string
237			if err := json.Unmarshal(data, &items); err != nil {
238				return nil, err
239			}
240			return normalizeReadinessStringList(items), nil
241		case '"':
242			var item string
243			if err := json.Unmarshal(data, &item); err != nil {
244				return nil, err
245			}
246			if splitLines {
247				return normalizeReadinessStringList(strings.Split(item, "\n")), nil
248			}
249			return normalizeReadinessStringList([]string{item}), nil
250		default:
251			return nil, fmt.Errorf("%s must be a string or string array", fieldName)
252		}
253	}
