541	func truncatePreClaimIntakePromptForLog(prompt string) string {
542		const limit = 32 * 1024
543		if len(prompt) <= limit {
544			return prompt
545		}
546		const marker = "\n...[readiness prompt truncated in worker log; full prompt is in the service session log]...\n"
547		head := (limit - len(marker)) / 2
548		tail := limit - len(marker) - head
549		if head <= 0 || tail <= 0 {
550			return prompt[:limit]
551		}
552		return prompt[:head] + marker + prompt[len(prompt)-tail:]
553	}
