603		env := preClaimIntakePromptEnvelope{
604			Title:         strings.TrimSpace(b.Title),
605			Description:   strings.TrimSpace(b.Description),
606			Acceptance:    strings.TrimSpace(b.Acceptance),
607			Notes:         strings.TrimSpace(b.Notes),
608			Labels:        append([]string(nil), b.Labels...),
609			PriorAttempts: []preClaimIntakeAttempt{},
610			Depth:         beadDecompositionDepth(projectRoot, b),
611			Parent:        strings.TrimSpace(b.Parent),
612			Dependencies:  append([]string(nil), b.DepIDs()...),
613		}
614	
615		// Prior attempts are optional for the gate. If bead history is available,
616		// include the last few attempt/result summaries to help the classifier
617		// distinguish a first-pass atomic bead from repeated decomposition.
618		if store != nil {
619			if eventStore, ok := any(store).(interface {
620				Events(id string) ([]bead.BeadEvent, error)
621			}); ok {
