623					for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
624						ev := events[i]
625						if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
626							continue
627						}
628						env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
629							Status:    strings.TrimSpace(ev.Summary),
630							Rationale: strings.TrimSpace(ev.Body),
631						})
632					}
633				}
634			}
635		}
636	
637		body, err := json.MarshalIndent(env, "", "  ")
638		if err != nil {
639			return "", err
640		}
641	
642		var sb strings.Builder
643		sb.WriteString("MODE: intake\n")
644		sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
645		sb.WriteString("Do not rewrite bead fields in intake mode. If the bead is executable as written, classify it as ready even when the prose could be cleaner.\n")
646		sb.WriteString("Canonical schema: " + readinessChecksSchemaPath + ". Treat it as the source of truth for readiness_checks[].verdict and for forward-compatible extra fields.\n")
647		sb.WriteString("readiness_checks[].verdict may be a JSON bool, string, null, or omitted; match the schema and the Go decoder contract exactly.\n")
648		sb.WriteString("Return exactly one JSON object matching the readiness schema with classification, tractability, score, rationale, difficulty, readiness_checks, suggested_fixes, rewrite, suggested_child_beads, and waivers_applied.\n")
649		sb.WriteString("readiness_checks MUST be a JSON array; it may be empty, and every entry MUST be an object with reason, verdict, evidence, and checkable_before_attempt. It must not be an object or string.\n")
650		sb.WriteString("suggested_fixes MUST be a JSON array; use a flat string list for prompt-quality suggestions, or an empty array when none apply.\n")
651		sb.WriteString("suggested_child_beads MUST be a JSON array of objects. When a child includes acceptance, prefer a JSON string array of numbered criteria; the decoder tolerates a single string fallback, but do not rely on it.\n")
652		sb.WriteString("waivers_applied MUST be a JSON array. Prefer waiver objects with reason, criteria, and evidence; the decoder tolerates a flat string list fallback, but do not rely on it.\n")
653		sb.WriteString("difficulty MUST be an object with estimated_difficulty and reason. estimated_difficulty MUST be exactly one of easy, medium, or hard.\n")
654		sb.WriteString("Use medium as the default implementation difficulty when uncertain or when the task is ordinary build/test/code work; medium maps to standard dispatch.\n")
655		sb.WriteString("Use easy only for work suitable for cheap dispatch: narrow mechanical edits such as typo fixes, formatting, simple docs/prose tweaks, straightforward fixture updates, or one-file transforms with low blast radius.\n")
656		sb.WriteString("Use hard only for work suitable for smart dispatch: architecture or ambiguous tradeoff judgment, multiple subsystems with high blast radius, security/data-loss/concurrency risk, or prior attempts showing standard power is insufficient.\n")
657		sb.WriteString("Do not choose hard just because a bead is important, long, or could be written more cleanly. Readiness score and difficulty are separate: low readiness means refine/split/block, not hard.\n")
658		sb.WriteString("If the bead is not executable as written but can be made executable by a narrow, semantics-preserving metadata/AC rewrite, emit rewrite with changed_fields, description, and acceptance.\n")
659		sb.WriteString("Put prompt-quality improvements in suggested_fixes only; keep operator_required for actual blockers.\n")
660		sb.WriteString("Preservation rules: non-scope items, governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, and dependency IDs (ddx-XXXXXXXX) must all appear in the replacement description.\n")
661		sb.WriteString("Classify as operator_required only when ambiguity, missing prerequisites, hidden external blockers, or unsafe scope choices prevent an implementation attempt.\n")
662		sb.WriteString("Stale-blocker precedence: if bead notes or a reopen event since the last blocker prior_attempt explicitly state the blocker was cleared, resolved, or unblocked, treat that prior_attempt blocker as historical context only. Do not classify the bead as operator_required or blocked based on a stale prior_attempt event alone when notes or a reopen since that event explicitly cleared it. A newer note or reopen supersedes an older blocker prior_attempt unless current cheap evidence revalidates the blocker.\n")
663		sb.WriteString("Do not include prose or markdown.\n\n")
664		sb.WriteString("```json\n")
665		sb.Write(body)
666		sb.WriteString("\n```\n")
667		return sb.String(), nil
668	}
