 31	func dispatchLifecycleRun(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
 32		scratchDir, err := newLifecycleScratchDir(projectRoot)
 33		if err != nil {
 34			return nil, fmt.Errorf("lifecycle dispatch: create scratch workdir: %w", err)
 35		}
 36		defer func() {
 37			// Deregister the seeded worktree (no-op/ignored if the fallback empty
 38			// repo was used) before removing the directory, so it does not linger
 39			// in the project's worktree registry.
 40			_ = internalgit.Command(context.Background(), projectRoot, "worktree", "remove", "--force", scratchDir).Run()
 41			_ = os.RemoveAll(scratchDir)
 42		}()
 43	
 44		runtime.WorkDir = scratchDir
 45		runtime.PermissionsOverride = PermissionsReadOnlyLifecycle
 46	
 47		before, err := captureLifecycleProjectStatus(projectRoot)
 48		if err != nil {
 49			return nil, err
 50		}
 51	
 52		result, dispatchErr := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
 53	
 54		beadID := ""
 55		if runtime.Correlation != nil {
 56			beadID = strings.TrimSpace(runtime.Correlation["bead_id"])
 57		}
 58		if guardErr := guardLifecycleProjectStatus(projectRoot, before, beadID); guardErr != nil {
 59			return nil, guardErr
 60		}
 61		if dispatchErr != nil {
 62			return nil, dispatchErr
 63		}
 64		return result, nil
 65	}
