 67	func newLifecycleScratchDir(projectRoot string) (string, error) {
 68		dir, err := config.MkdirExecutionScratch(projectRoot, lifecycleScratchDirPrefix)
 69		if err != nil {
 70			return "", err
 71		}
 72		// Seed the scratch workdir from the project's HEAD so the readiness-check
 73		// classifier sees the project's real source files rather than an empty repo
 74		// — otherwise file-presence checks block every bead (ddx-efadca32). A
 75		// detached worktree keeps the classifier isolated from the master worktree
 76		// (it cannot mutate tracked files there). git worktree add must create the
 77		// directory itself, so clear the placeholder MkdirExecutionScratch made.
 78		if rmErr := os.RemoveAll(dir); rmErr != nil {
 79			return "", fmt.Errorf("reset lifecycle scratch dir: %w", rmErr)
 80		}
 81		if out, addErr := internalgit.Command(context.Background(), projectRoot, "worktree", "add", "--detach", dir, "HEAD").CombinedOutput(); addErr != nil {
 82			// HEAD may be unborn (a project with no commits yet); readiness has
 83			// nothing to check there, so fall back to an empty scratch repo.
 84			if mkErr := os.MkdirAll(dir, 0o700); mkErr != nil {
 85				return "", fmt.Errorf("recreate lifecycle scratch dir after worktree add failed (%s): %w", strings.TrimSpace(string(out)), mkErr)
 86			}
 87			if out2, initErr := internalgit.Command(context.Background(), dir, "init", "-q").CombinedOutput(); initErr != nil {
 88				_ = os.RemoveAll(dir)
 89				return "", fmt.Errorf("initialize lifecycle scratch git repo: %s: %w", strings.TrimSpace(string(out2)), initErr)
 90			}
 91		}
 92		return dir, nil
 93	}
