 95	func captureLifecycleProjectStatus(projectRoot string) (lifecycleProjectStatusSnapshot, error) {
 96		if strings.TrimSpace(projectRoot) == "" {
 97			return lifecycleProjectStatusSnapshot{}, nil
 98		}
 99		if _, err := os.Stat(filepath.Join(projectRoot, ".git")); err != nil {
100			if os.IsNotExist(err) {
101				return lifecycleProjectStatusSnapshot{}, nil
102			}
103			return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: stat project root .git: %w", err)
104		}
105		repair := gitrepohealth.RepairKnownConfigCorruption(context.Background(), projectRoot)
106		if !repair.StatusSucceeded {
107			detail := strings.TrimSpace(firstNonEmpty(repair.StatusStderr, repair.StatusOutput))
108			return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: snapshot project root dirtiness: %s", detail)
109		}
110		out, err := internalgit.Command(context.Background(), projectRoot, "status", "--porcelain", "--untracked-files=all").CombinedOutput()
111		if err != nil {
112			return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: snapshot project root dirtiness: %s: %w", strings.TrimSpace(string(out)), err)
113		}
114		return lifecycleProjectStatusSnapshot{
115			available: true,
116			entries:   parseLifecycleProjectStatus(string(out)),
117		}, nil
118	}
