120	func parseLifecycleProjectStatus(raw string) map[string]string {
121		entries := map[string]string{}
122		for _, line := range strings.Split(raw, "\n") {
123			line = strings.TrimRight(line, "\r")
124			if len(line) < 4 || strings.TrimSpace(line) == "" {
125				continue
126			}
127			status := line[:2]
128			path := strings.TrimSpace(line[3:])
129			if idx := strings.Index(path, " -> "); idx >= 0 {
130				path = strings.TrimSpace(path[idx+4:])
131			}
132			if path == "" {
133				continue
134			}
135			entries[path] = status
136		}
137		return entries
138	}
