140	func guardLifecycleProjectStatus(projectRoot string, before lifecycleProjectStatusSnapshot, beadID string) error {
141		if !before.available {
142			return nil
143		}
144		after, err := captureLifecycleProjectStatus(projectRoot)
145		if err != nil {
146			return err
147		}
148		if lifecycleProjectStatusEqual(before.entries, after.entries) {
149			return nil
150		}
151	
152		newPaths, changedPaths := diffLifecycleProjectStatus(before.entries, after.entries)
153		if len(newPaths) > 0 {
154			if err := restoreLifecycleProjectMutations(projectRoot, after.entries, newPaths); err != nil {
155				return err
156			}
157			restored, restoreErr := captureLifecycleProjectStatus(projectRoot)
158			if restoreErr != nil {
159				return restoreErr
160			}
161			after = restored
162			newPaths, changedPaths = diffLifecycleProjectStatus(before.entries, after.entries)
163		}
164		if len(newPaths) == 0 && len(changedPaths) == 0 {
165			if beadID != "" {
166				return fmt.Errorf("lifecycle dispatch: project root mutation rejected for bead %s", beadID)
167			}
168			return fmt.Errorf("lifecycle dispatch: project root mutation rejected")
169		}
170	
171		var details []string
172		if len(newPaths) > 0 {
173			details = append(details, "new dirty paths: "+strings.Join(newPaths, ", "))
174		}
175		if len(changedPaths) > 0 {
176			details = append(details, "changed existing dirty paths: "+strings.Join(changedPaths, ", "))
177		}
178		if beadID != "" {
179			return fmt.Errorf("lifecycle dispatch: project root mutation rejected for bead %s (%s)", beadID, strings.Join(details, "; "))
