196	func diffLifecycleProjectStatus(before, after map[string]string) (newPaths []string, changedPaths []string) {
197		for path, afterStatus := range after {
198			beforeStatus, ok := before[path]
199			if !ok {
200				newPaths = append(newPaths, path)
201				continue
202			}
203			if beforeStatus != afterStatus {
204				changedPaths = append(changedPaths, path)
205			}
206		}
207		for path := range before {
208			if _, ok := after[path]; !ok {
209				changedPaths = append(changedPaths, path)
210			}
211		}
212		sort.Strings(newPaths)
213		sort.Strings(changedPaths)
214		return newPaths, changedPaths
215	}
