217	func restoreLifecycleProjectMutations(projectRoot string, after map[string]string, newPaths []string) error {
218		var restorePaths []string
219		var cleanPaths []string
220		for _, path := range newPaths {
221			if after[path] == "??" {
222				cleanPaths = append(cleanPaths, path)
223				continue
224			}
225			restorePaths = append(restorePaths, path)
226		}
227	
228		if len(restorePaths) > 0 {
229			args := []string{"restore", "--source=HEAD", "--staged", "--worktree", "--"}
230			args = append(args, restorePaths...)
231			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
232				return fmt.Errorf("lifecycle dispatch: restore project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
233			}
234		}
235		if len(cleanPaths) > 0 {
236			args := []string{"clean", "-fd", "--"}
237			args = append(args, cleanPaths...)
238			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
239				return fmt.Errorf("lifecycle dispatch: clean project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
240			}
241		}
242		return nil
243	}

