 16	// ACQualityItem holds the classification of one parsed AC line.
 17	type ACQualityItem struct {
 18		AC         int    `json:"ac"`
 19		Text       string `json:"text"`
 20		Kind       string `json:"kind"`
 21		Verifiable bool   `json:"verifiable"`
 22	}
