 24	// ACQualityResult is the verifiability assessment of a bead's acceptance text.
 25	// Score = VerifiableCount / Total; PassesThreshold = Score >= Threshold.
 26	type ACQualityResult struct {
 27		Score           float64         `json:"score"`
 28		VerifiableCount int             `json:"verifiable_count"`
 29		ProseCount      int             `json:"prose_count"`
 30		Total           int             `json:"total"`
 31		Items           []ACQualityItem `json:"items"`
 32		PassesThreshold bool            `json:"passes_threshold"`
 33		Threshold       float64         `json:"threshold"`
 34	}
