 80	// MarkBeadACQualityLow emits the low-quality evidence event and, when block is
 81	// true, sets execution-eligible=false so the bead leaves ReadyExecution.
 82	// Safe to call more than once (idempotent label add; events are append-only).
 83	func MarkBeadACQualityLow(store BeadACQualityStore, beadID string, result ACQualityResult, block bool) error {
 84		if err := store.Update(context.Background(), beadID, func(b *bead.Bead) {
 85			if b.Extra == nil {
 86				b.Extra = make(map[string]any)
 87			}
 88			if block {
 89				b.Extra["execution-eligible"] = false
 90			}
 91			if !beadHasACQualityLabel(b.Labels) {
 92				b.Labels = append(b.Labels, "ac-quality:needs-refinement")
 93			}
 94		}); err != nil {
 95			return fmt.Errorf("ac-quality: update bead: %w", err)
 96		}
 97		body, _ := json.Marshal(result.Items)
 98		return store.AppendEvent(beadID, bead.BeadEvent{
 99			Kind: "ac-quality-low",
100			Summary: fmt.Sprintf("score=%.2f threshold=%.2f verifiable=%d/%d",
101				result.Score, result.Threshold, result.VerifiableCount, result.Total),
102			Body:   string(body),
103			Source: "preclaim-ac-quality",
104		})
105	}
