543		cutoff := now.Add(-ProviderUnavailableCooldown)
544		seen := map[string]struct{}{}
545		for _, b := range beads {
546			for _, failed := range readFailedRoutes(b.Extra) {
547				at, _ := time.Parse(time.RFC3339, strings.TrimSpace(failed.At))
548				if at.IsZero() {
