253	func lintPromptSafeCustomValue(v any) (any, bool) {
254		switch val := v.(type) {
255		case nil:
256			return nil, true
257		case string:
258			if len(val) > 4096 {
259				return nil, false
260			}
261			return val, true
262		case bool, int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
263			return val, true
264		case []string:
265			if len(val) > 32 {
266				return nil, false
267			}
268			cp := make([]string, 0, len(val))
269			for _, item := range val {
270				if len(item) > 512 {
271					return nil, false
272				}
273				cp = append(cp, item)
274			}
275			return cp, true
276		case []any:
277			if len(val) > 32 {
278				return nil, false
279			}
280			cp := make([]string, 0, len(val))
281			for _, item := range val {
282				s, ok := item.(string)
283				if !ok || len(s) > 512 {
284					return nil, false
285				}
286				cp = append(cp, s)
287			}
288			return cp, true
289		default:
290			return nil, false
291		}
292	}
